 1	import React, { FC } from 'react';
 2	
 3	import { IoK8sApiCoreV1Pod } from '@kubevirt-ui/kubevirt-api/kubernetes';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { isEmpty } from '@kubevirt-utils/utils/utils';
 6	import {
 7	  Alert,
 8	  AlertVariant,
 9	  ProgressStep,
10	  ProgressStepper,
11	  ProgressStepVariant,
12	  Stack,
13	} from '@patternfly/react-core';
14	
15	import { STATUS_TO_PROGRESS_VARIANT, UPLOAD_STATUSES } from './constants';
16	import { exportFailed, exportInProgress } from './utils';
17	
18	type ShowProgressProps = {
19	  uploadPod: IoK8sApiCoreV1Pod;
20	};
21	
22	const ShowProgress: FC<ShowProgressProps> = ({ uploadPod }) => {
23	  const { t } = useKubevirtTranslation();
24	
25	  const phase = uploadPod?.status?.phase;
26	  const progressStatus = STATUS_TO_PROGRESS_VARIANT[phase];
27	  const isFailed = exportFailed(uploadPod);
28	  const isInProgress = exportInProgress(uploadPod);
29	
30	  if (isEmpty(uploadPod)) return null;
31	
32	  return (
33	    <Stack className="kv-exportmodal__showprogress" hasGutter>
34	      <ProgressStepper aria-label="Upload steps" isCenterAligned>
35	        <ProgressStep
36	          aria-label={t('Started')}
37	          id="upload-step-1"
38	          titleId="Started"
39	          variant={ProgressStepVariant.success}
40	        >
41	          {t('Started')}
42	        </ProgressStep>
43	        <ProgressStep
44	          aria-label={isFailed ? t('Failed') : t('In process')}
45	          id="upload-step-2"
46	          isCurrent
47	          titleId="In process"
48	          variant={progressStatus}
49	        >
50	          {isFailed ? t('Failed') : t('In process')}
51	        </ProgressStep>
52	        <ProgressStep
53	          variant={
54	            phase === UPLOAD_STATUSES.SUCCEEDED
55	              ? ProgressStepVariant.success
56	              : ProgressStepVariant.pending
57	          }
58	          aria-label={t('Completed')}
59	          id="upload-step-3"
60	          titleId="Completed"
61	        >
62	          {t('Completed')}
63	        </ProgressStep>
64	      </ProgressStepper>
65	
66	      {isFailed && (
67	        <Alert
68	          isInline
69	          title={t('An error occurred during the upload process')}
70	          variant={AlertVariant.danger}
71	        >
72	          {uploadPod?.status?.conditions?.find((c) => c.status === 'True')?.message || 'unknown'}
73	        </Alert>
74	      )}
75	
76	      {isInProgress && (
77	        <Alert
78	          isInline
79	          title={t('The upload process will continue after you close the modal.')}
80	          variant={AlertVariant.info}
81	        ></Alert>
82	      )}
83	    </Stack>
84	  );
85	};
86	
87	export default ShowProgress;

